457→/// Convert a git2::Diff into our FileDiff structs
458→fn collect_diff_files(diff: &git2::Diff) -> Result<Vec<FileDiff>, String> {
459→    let mut files: Vec<FileDiff> = Vec::new();
460→
461→    diff.print(git2::DiffFormat::Patch, |delta, hunk, line| {
462→        let path = delta
463→            .new_file()
464→            .path()
465→            .or_else(|| delta.old_file().path())
466→            .map(|p| p.to_string_lossy().to_string())
467→            .unwrap_or_default();
468→
469→        let status = match delta.status() {
470→            git2::Delta::Added => "added",
471→            git2::Delta::Deleted => "deleted",
472→            _ => "modified",
473→        };
474→
475→        // Ensure we have a FileDiff entry for this path
476→        if files.last().map_or(true, |f| f.path != path) {
477→            files.push(FileDiff {
478→                path: path.clone(),
479→                status: status.to_string(),
480→                hunks: Vec::new(),
481→            });
482→        }
483→
484→        let file = files.last_mut().unwrap();
485→
486→        // New hunk
487→        if let Some(h) = hunk {
488→            let header = std::str::from_utf8(h.header()).unwrap_or("").to_string();
489→            if file.hunks.last().map_or(true, |last| last.header != header) {
490→                file.hunks.push(DiffHunk {
491→                    header,
492→                    lines: Vec::new(),
493→                });
494→            }
495→        }
496→
497→        // Diff line
498→        if let Some(current_hunk) = file.hunks.last_mut() {
499→            let kind = match line.origin() {
500→                '+' => "add",
501→                '-' => "delete",
502→                ' ' => "context",
503→                _ => return true,
504→            };
505→            let content = std::str::from_utf8(line.content()).unwrap_or("").to_string();
506→            current_hunk.lines.push(DiffLine {
507→                kind: kind.to_string(),
508→                content,
509→                old_lineno: line.old_lineno(),
510→                new_lineno: line.new_lineno(),
511→            });
512→        }
513→
514→        true
515→    })
516→    .map_err(|e| format!("Failed to print diff: {}", e))?;
517→
518→    Ok(files)
519→}
