521→fn collect_checkpoint_diff(
522→    repo: &git2::Repository,
523→    commit_sha: &str,
524→) -> Result<Vec<FileDiff>, String> {
525→    let oid = git2::Oid::from_str(commit_sha)
526→        .map_err(|e| format!("Invalid commit SHA: {}", e))?;
527→    let commit = repo
528→        .find_commit(oid)
529→        .map_err(|e| format!("Commit not found: {}", e))?;
530→
531→    let tree = commit
532→        .tree()
533→        .map_err(|e| format!("Failed to get tree: {}", e))?;
534→
535→    let parent_tree = commit.parent(0).ok().and_then(|p| p.tree().ok());
536→
537→    let diff = repo
538→        .diff_tree_to_tree(parent_tree.as_ref(), Some(&tree), None)
539→        .map_err(|e| format!("Failed to compute diff: {}", e))?;
540→
541→    collect_diff_files(&diff)
542→}
