544→fn load_sanitized_checkpoint_transcripts(
545→    repo: &git2::Repository,
546→    checkpoint_id: &str,
547→) -> Result<Vec<semantic_review::PromptTranscriptSession>, String> {
548→    let prefix = &checkpoint_id[..2];
549→    let suffix = &checkpoint_id[2..];
550→    let meta_path = format!("{}/{}/metadata.json", prefix, suffix);
551→    let meta_content = read_blob(repo, &meta_path)?;
552→    let meta = serde_json::from_str::<CheckpointReviewMetadata>(&meta_content)
553→        .map_err(|e| format!("Failed to parse checkpoint metadata: {}", e))?;
554→
555→    let session_count = meta.sessions.map(|sessions| sessions.len()).unwrap_or(0);
556→    let mut all_sessions = Vec::new();
557→
558→    for session_index in 0..session_count {
559→        let candidates =
560→            transcript_candidate_paths(checkpoint_id, session_index as u32, Some(&meta_content));
561→        let mut transcript_content = None;
562→        for path in candidates {
563→            if let Ok(content) = read_blob(repo, &path) {
564→                transcript_content = Some(content);
565→                break;
566→            }
567→        }
568→
569→        let Some(content) = transcript_content else {
570→            continue;
571→        };
572→
573→        let parsed = session::read_transcript(&content);
574→        let sanitized = session::sanitize_transcript_for_semantic_review(&parsed, 4_000);
575→        if sanitized.is_empty() {
576→            continue;
577→        }
578→
579→        all_sessions.push(semantic_review::PromptTranscriptSession {
580→            session_index: session_index as u32,
581→            messages: sanitized
582→                .into_iter()
583→                .map(|message| semantic_review::PromptTranscriptMessage {
584→                    role: message.role,
585→                    content: message.content,
586→                })
587→                .collect(),
588→        });
589→    }
590→
591→    Ok(all_sessions)
592→}
