698→#[tauri::command]
699→fn get_branch_diff(
700→    repo_path: String,
701→    branch: String,
702→) -> Result<Vec<FileDiff>, String> {
703→    let repo = git::open_repo(&repo_path)?;
704→
705→    // Resolve the branch HEAD
706→    let branch_ref = repo
707→        .find_branch(&branch, git2::BranchType::Local)
708→        .map_err(|e| format!("Branch not found: {}", e))?;
709→    let branch_commit = branch_ref
710→        .get()
711→        .peel_to_commit()
712→        .map_err(|e| format!("Failed to resolve branch HEAD: {}", e))?;
713→
714→    // Find the default branch (try main, then master)
715→    let default_branch_name = if repo.find_branch("main", git2::BranchType::Local).is_ok() {
716→        "main"
717→    } else if repo.find_branch("master", git2::BranchType::Local).is_ok() {
718→        "master"
719→    } else {
720→        return Err("No default branch (main/master) found".to_string());
721→    };
722→
723→    // If we're diffing the default branch against itself, return empty
724→    if branch == default_branch_name {
725→        return Ok(Vec::new());
726→    }
727→
728→    let default_ref = repo
729→        .find_branch(default_branch_name, git2::BranchType::Local)
730→        .map_err(|e| format!("Default branch error: {}", e))?;
731→    let default_commit = default_ref
732→        .get()
733→        .peel_to_commit()
734→        .map_err(|e| format!("Failed to resolve default branch: {}", e))?;
735→
736→    // Find merge base
737→    let merge_base_oid = repo
738→        .merge_base(default_commit.id(), branch_commit.id())
739→        .map_err(|e| format!("Failed to find merge base: {}", e))?;
740→    let merge_base_commit = repo
741→        .find_commit(merge_base_oid)
742→        .map_err(|e| format!("Failed to find merge base commit: {}", e))?;
743→
744→    let base_tree = merge_base_commit
745→        .tree()
746→        .map_err(|e| format!("Failed to get base tree: {}", e))?;
747→    let branch_tree = branch_commit
748→        .tree()
749→        .map_err(|e| format!("Failed to get branch tree: {}", e))?;
750→
751→    let diff = repo
752→        .diff_tree_to_tree(Some(&base_tree), Some(&branch_tree), None)
753→        .map_err(|e| format!("Failed to compute branch diff: {}", e))?;
754→
755→    collect_diff_files(&diff)
756→}
