759→fn watch_repo(
760→    repo_path: String,
761→    app: tauri::AppHandle,
762→    state: State<'_, Mutex<AppState>>,
763→) -> Result<(), String> {
764→    let mut app_state = state.lock().map_err(|_| "State lock error".to_string())?;
765→
766→    // Don't double-watch
767→    if app_state.watched_repos.contains(&repo_path) {
768→        return Ok(());
769→    }
770→    app_state.watched_repos.insert(repo_path.clone());
771→
772→    let app_handle = app.clone();
773→    let repo_path_for_closure = repo_path.clone();
774→    watcher::watch_repo(&repo_path, move |event| {
775→        let event_name = match event {
776→            watcher::WatchEvent::CheckpointChanged => "checkpoint-changed",
777→            watcher::WatchEvent::SessionChanged(_) => "session-changed",
778→            watcher::WatchEvent::ConfigChanged => "config-changed",
779→        };
780→        let _ = app_handle.emit(event_name, serde_json::json!({
781→            "repoPath": repo_path_for_closure,
782→        }));
783→    })?;
784→
785→    Ok(())
