788→#[cfg_attr(mobile, tauri::mobile_entry_point)]
789→pub fn run() {
790→    tauri::Builder::default()
791→        .plugin(tauri_plugin_opener::init())
792→        .plugin(tauri_plugin_dialog::init())
793→        .plugin(tauri_plugin_window_state::Builder::default().build())
794→        .manage(Mutex::new(AppState {
795→            pty_manager: pty::PtyManager::new(),
796→            watched_repos: HashSet::new(),
797→        }))
798→        .manage(Mutex::new(ghostty::GhosttyState::new()))
799→        .setup(|app| {
800→            // Start the ghostty tick loop on the MAIN THREAD via a Cocoa timer.
801→            // ghostty_app_tick processes Cocoa/Metal events and must run on the
802→            // main thread.
803→            {
804→                use block2::RcBlock;
805→                use objc2_foundation::NSTimer;
806→
807→                let handle = app.handle().clone();
808→                let tick_block = RcBlock::new(move |_timer| {
809→                    let state = handle.state::<Mutex<ghostty::GhosttyState>>();
810→                    let mutex = state.inner();
811→                    if let Ok(gs) = mutex.lock() {
812→                        if let Some(app) = gs.app.as_ref() {
813→                            app.tick();
814→                        }
815→                    }
816→                });
817→
818→                let _tick_timer = unsafe {
819→                    NSTimer::scheduledTimerWithTimeInterval_repeats_block(
820→                        1.0 / 60.0,
821→                        true,
822→                        &tick_block,
823→                    )
824→                };
825→            }
826→
827→            // System tray
828→            use tauri::menu::{MenuBuilder, MenuItemBuilder};
829→            use tauri::tray::TrayIconBuilder;
830→            use tauri::Manager;
831→
832→            let show = MenuItemBuilder::with_id("show", "Show Entire").build(app)?;
833→            let quit = MenuItemBuilder::with_id("quit", "Quit").build(app)?;
834→            let menu = MenuBuilder::new(app)
835→                .item(&show)
836→                .separator()
837→                .item(&quit)
838→                .build()?;
839→
840→            let _tray = TrayIconBuilder::new()
841→                .tooltip("Entire Desktop")
842→                .menu(&menu)
843→                .on_menu_event(move |app, event| {
844→                    match event.id().as_ref() {
845→                        "show" => {
846→                            if let Some(window) = app.get_webview_window("main") {
847→                                let _ = window.show();
848→                                let _ = window.set_focus();
849→                            }
850→                        }
851→                        "quit" => {
852→                            app.exit(0);
853→                        }
854→                        _ => {}
855→                    }
856→                })
857→                .on_tray_icon_event(|tray, event| {
858→                    if let tauri::tray::TrayIconEvent::Click { .. } = event {
859→                        let app = tray.app_handle();
860→                        if let Some(window) = app.get_webview_window("main") {
861→                            let _ = window.show();
862→                            let _ = window.set_focus();
863→                        }
864→                    }
865→                })
866→                .build(app)?;
867→
868→            Ok(())
869→        })
870→        .invoke_handler(tauri::generate_handler![
871→            debug_log,
