    #[test]
    fn transcript_candidates_fall_back_to_other_metadata_sessions() {
        let meta = r#"{
            "sessions": [
                { "transcript": "/76/5026ba9e43/0/full.jsonl" },
                { "transcript": "/76/5026ba9e43/1/full.jsonl" }
